async function loadMarketing(){const rows=await apiGet("Marketing");const tbody=document.getElementById("marketing-list");if(!rows.length){tbody.innerHTML=`<tr><td colspan="6"><div class="empty"><div class="empty-icon">📣</div><p>Chưa có ai trong danh sách marketing</p></div></td></tr>`;return;}tbody.innerHTML=rows .map((r)=> ` <tr> <td class="td-name">${r.name||""}</td> <td class="td-phone">${r.phone||""}</td> <td style="text-align:center;">${r.msg1SentAt ? `<span style="color:var(--green);font-size:.8rem">✅</span>`:`<button class="btn btn-ghost btn-sm" onclick="sendMsg('${r.id}',1,this)">Gửi</button>`}</td> <td style="text-align:center;">${r.msg2SentAt ? `<span style="color:var(--green);font-size:.8rem">✅</span>`:`<button class="btn btn-ghost btn-sm" onclick="sendMsg('${r.id}',2,this)">Gửi</button>`}</td> <td style="text-align:center;">${r.msg3SentAt ? `<span style="color:var(--green);font-size:.8rem">✅</span>`:`<button class="btn btn-ghost btn-sm" onclick="sendMsg('${r.id}',3,this)">Gửi</button>`}</td> <td style="text-align:center;">${r.zaloImported ? '<span class="badge badge-purple" style="font-size:.72rem;width:58px;">Zalo ✓</span>':'<span class="badge" style="font-size:.72rem;background:rgba(100,116,139,.12);color:#64748b">Chưa nhập</span>'}</td> </tr>`,).join("");}async function sendMsg(id,num,btn){const content=document.getElementById(`msg${num}-content`).value;if(!content.trim()){toast("Vui lòng nhập nội dung tin nhắn","error");return;}setLoading(btn,true,null,"Đang gởi tin nhắn");const field=`msg${num}SentAt`;await apiPost("update","Marketing",{id,updates:{[field]:new Date().toISOString()},});toast(`Đã gửi tin nhắn ${num}`,"success");await loadMarketing();}async function sendBulkMsg(num){const btn=document.querySelector(`[onclick="sendBulkMsg(${num})"]`);setLoading(btn,true,null,"Đang gởi tin nhắn hàng loạt");const rows=await apiGet("Marketing");const field=`msg${num}SentAt`;const unsent=rows.filter((r)=> !r[field]);if(!unsent.length){setLoading(btn,false);toast(`Tất cả đã nhận Tin nhắn ${num}`,"info");return;}for(const r of unsent){await apiPost("update","Marketing",{id:r.id,updates:{[field]:new Date().toISOString()},});}setLoading(btn,false);toast(`Đã gửi Tin nhắn ${num}cho ${unsent.length}người`,"success");await loadMarketing();}async function markZaloImported(){const btn=document.querySelector('[onclick="markZaloImported()"]');setLoading(btn,true,null,"Đang ghi nhận thông tin đã nhập");const rows=await apiGet("Marketing");for(const r of rows){if(!r.zaloImported)await apiPost("update","Marketing",{id:r.id,updates:{zaloImported:true},});}setLoading(btn,false);toast("Đã đánh dấu toàn bộ đã nhập Zalo Marketing","success");await loadMarketing();}async function exportExcel(){const btn=document.querySelector('[onclick="exportExcel()"]');setLoading(btn,true,null,"Đang xuất dữ liệu ra CSV");const rows=await apiGet("Marketing");const parts=await apiGet("Participants","status","consulted");const cons=await apiGet("Consultations");if(!rows.length){setLoading(btn,false);toast("Không có dữ liệu để xuất","error");return;}const headers=["ID","Họ tên","Số điện thoại","Năm sinh","Giới tính","Chẩn đoán","Sản phẩm","Kết quả tư vấn","Tin 1","Tin 2","Tin 3",];const csvRows=[headers.join(",")];rows.forEach((r)=>{const p=parts.find((x)=> x.id===r.participantId)||{};const c=cons.find((x)=> x.participantId===r.participantId)||{};csvRows.push([r.participantId,`"${r.name||""}"`,r.phone||"",p.birthYear||"",p.gender||"",`"${c.diagnosis||""}"`,`"${c.product||""}"`,`"${c.outcome||""}"`,r.msg1SentAt ? "Đã gửi":"Chưa",r.msg2SentAt ? "Đã gửi":"Chưa",r.msg3SentAt ? "Đã gửi":"Chưa",].join(","),);});const blob=new Blob(["\uFEFF" + csvRows.join("\n")],{type:"text/csv;charset=utf-8",});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=`marketing-${new Date().toISOString().slice(0,10)}.csv`;a.click();URL.revokeObjectURL(url);const pIds=[...new Set(rows.map((r)=> r.participantId))];for(const pid of pIds){await apiPost("update","Participants",{id:pid,updates:{status:"marketed"},});}setLoading(btn,false);toast("Đã xuất file Excel(CSV)","success");}